SELECT [ReportVendutoComprato-NonProiettato-Vendite].Linea, [ReportVendutoComprato-NonProiettato-Vendite].Articolo, [ReportVendutoComprato-NonProiettato-Vendite].CodiceColore, [ReportVendutoComprato-NonProiettato-Vendite].Colore, [ReportVendutoComprato-NonProiettato-Vendite].Marchio, [ReportVendutoComprato-NonProiettato-Vendite].Stagione, [ReportVendutoComprato-NonProiettato-Vendite].[delete reason], 0 AS paiacomprate, [ReportVendutoComprato-NonProiettato-Vendite].PaiaVendute, [ReportVendutoComprato-NonProiettato-Vendite].Descrizione, [ReportVendutoComprato-NonProiettato-Vendite].Descrizione2, [ReportVendutoComprato-NonProiettato-Vendite].FamigliaProdotto, [ReportVendutoComprato-NonProiettato-Vendite].GenereProdotto, [ReportVendutoComprato-NonProiettato-Vendite].[Collection Code], [ReportVendutoComprato-NonProiettato-Vendite].[Vendor No_], [ReportVendutoComprato-NonProiettato-Vendite].VendorName, [ReportVendutoComprato-NonProiettato-Acquisti].[Document Type], [ReportVendutoComprato-NonProiettato-Vendite].Manufacturer, [ReportVendutoComprato-NonProiettato-Vendite].ManufacturerName
FROM [ReportVendutoComprato-NonProiettato-Acquisti] RIGHT JOIN [ReportVendutoComprato-NonProiettato-Vendite] ON ([ReportVendutoComprato-NonProiettato-Acquisti].CodiceColore = [ReportVendutoComprato-NonProiettato-Vendite].CodiceColore) AND ([ReportVendutoComprato-NonProiettato-Acquisti].Articolo = [ReportVendutoComprato-NonProiettato-Vendite].Articolo)
WHERE ((([ReportVendutoComprato-NonProiettato-Acquisti].[Document Type]) Is Null));

